import React, { useState } from 'react';
import ImportDataSidebar from './ImportDataSidebar'; // Importing the sidebar component
import './ChatBox.css';

function ChatBox() {
  const [userStory, setUserStory] = useState('');
  const [messages, setMessages] = useState([]);
  const [isSidebarVisible, setIsSidebarVisible] = useState(false);
  const [jiraData, setJiraData] = useState([]); // Data fetched from Jira

  // Handle message input from user
  const handleMessageChange = (e) => {
    setUserStory(e.target.value);
  };

  // Handle sending the user story message (chat-like)
  const handleSendMessage = () => {
    if (userStory.trim()) {
      setMessages([...messages, { text: userStory, isUserMessage: true }]);
      setUserStory('');
    }
  };

  // Simulate importing data from Jira
  const handleImportData = () => {
    // Simulated Jira data (replace this with real API request logic)
    const fetchedData = [
      { id: 1, story: 'User Story 1: As a user, I want to login to my account.' },
      { id: 2, story: 'User Story 2: As a user, I want to reset my password.' },
      { id: 3, story: 'User Story 3: As a user, I want to view my profile.' },
    ];
    setJiraData(fetchedData);
    setIsSidebarVisible(true); // Show the sidebar after importing data
  };

  // Handle selecting a user story from the sidebar
  const handleSelectUserStory = (story) => {
    setUserStory(story); // Set the selected story in the chat box
  };

  return (
    <div className="chat-container">
      {/* Chat box UI */}
      <div className="chat-box">
        <div className="chat-box-messages">
          {messages.map((message, index) => (
            <div
              key={index}
              className={`message ${message.isUserMessage ? 'user-message' : 'bot-message'}`}
            >
              {message.text}
            </div>
          ))}
        </div>
        <div className="chat-input-container">
          <textarea
            value={userStory}
            onChange={handleMessageChange}
            placeholder="Enter your user story here..."
            rows="4"
          />
          <button onClick={handleSendMessage}>Send</button>
        </div>
      </div>

      {/* Sidebar for importing Jira data */}
      {isSidebarVisible && <ImportDataSidebar jiraData={jiraData} onSelectUserStory={handleSelectUserStory} />}
      <button className="import-btn" onClick={handleImportData}>
        Import Data from Jira
      </button>
    </div>
  );
}

export default ChatBox;
